const s = context.panel.data.series[0];
const f = s.fields;

const tempField = f.find(field => field.name === "temperature");
const humField = f.find(field => field.name === "humidity");
const timeField = f.find(field => field.name === "time_sec");

const tempVals = tempField ? tempField.values.toArray() : [];
const humVals = humField ? humField.values.toArray() : [];
const timeVals = timeField ? timeField.values.toArray() : [];

const points = tempVals.map((_, i) => ({
  value: [tempVals[i], humVals[i], timeVals[i]],
  itemStyle: {
    color:
      tempVals[i] > 30 ? "#ff4d4f" :
        tempVals[i] >= 28 ? "#f2c744" :
          "#73bf69"
  }
}));

const linePoints = tempVals.map((_, i) => [
  tempVals[i],
  humVals[i],
  timeVals[i]
]);

return {
  backgroundColor: 'transparent',
  tooltip: {
    formatter: function (params) {
      const v = params.value || [];
      return `
        Temperature: ${Number(v[0]).toFixed(1)} °C<br/>
        Humidity: ${Number(v[1]).toFixed(1)} %<br/>
        Time: ${Number(v[2]).toFixed(0)} s
      `;
    }
  },
  xAxis3D: {
    type: 'value',
    name: 'Temperature (°C)'
  },
  yAxis3D: {
    type: 'value',
    name: 'Humidity (%)'
  },
  zAxis3D: {
    type: 'value',
    name: 'Time (s)'
  },
  grid3D: {
    boxWidth: 100,
    boxDepth: 80,
    viewControl: {
      projection: 'perspective',
      autoRotate: false
    }
  },
  series: [
    {
      type: 'scatter3D',
      symbolSize: 10,
      data: points
    },
    {
      type: 'line3D',
      data: linePoints,
      lineStyle: {
        width: 3,
        color: '#6aa9ff'
      }
    }
  ]
};
